        let high = n - 1;
        let res = i;
        while (low <= high) {
            let mid = Math.floor((low + high) / 2);
            if (nums[mid] <= target) {
                res = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        let currentLen = res - i + 1;
        if (currentLen > maxLen) {
            maxLen = currentLen;
        }
    }
    return n - maxLen;
}
